// Split the input selector into individual pseudo-classes
// Check if each pseudo-class is supported or not
// Return true if all pseudo-classes are supported, false otherwise
function validateSelector(selector) {
	var pseudoClasses = selector.split(':');
	var supportedPseudoClasses = new Set(['first-child', 'last-child', 'nth-child', 'checked', 'enabled']);
	for (var i = 1; i < pseudoClasses.length; i++) {
		if (!supportedPseudoClasses.has(pseudoClasses[i])) {
			return false;
		}
	}
	return true;
}

