class Solution:
	def validateSelector(self, selector: str) -> bool:
		pseudoClasses = selector.split(':')
		supportedPseudoClasses = {'first-child', 'last-child', 'nth-child', 'checked', 'enabled'}
		for i in range(1, len(pseudoClasses)):
			if pseudoClasses[i] not in supportedPseudoClasses:
				return False
		return True
